/// All observable events in the runtime
#[derive(Clone, Debug, PartialEq, Eq)]
pub enum TraceEvent {
    // === Time ===
    Tick {
        virtual_time: Time,
    },

    // === Task Lifecycle ===
    TaskSpawn {
        task_id: TaskId,
        region_id: RegionId,
        name: Option<String>,
        budget: Budget,
    },
    TaskPoll {
        task_id: TaskId,
        poll_count: u32,
    },
    TaskYield {
        task_id: TaskId,
        reason: YieldReason,
    },
    TaskCheckpoint {
        task_id: TaskId,
        cancel_observed: bool,
        mask_remaining: u32,
    },
    TaskComplete {
        task_id: TaskId,
        outcome_kind: OutcomeKind,  // Ok, Err, Cancelled, Panicked
        elapsed_virtual: Duration,
    },

    // === Region Lifecycle ===
    RegionOpen {
        region_id: RegionId,
        parent: Option<RegionId>,
        budget: Budget,
    },
    RegionCloseStart {
        region_id: RegionId,
    },
    RegionFinalizerRun {
        region_id: RegionId,
        finalizer_index: usize,
        is_async: bool,
    },
    RegionClose {
        region_id: RegionId,
        outcome_kind: OutcomeKind,
        children_count: usize,
        finalizers_run: usize,
    },

    // === Cancellation ===
    CancelRequest {
        target: CancelTarget,  // Region or Task
        reason: CancelReason,
        budget: Budget,
    },
    CancelPropagate {
        from: RegionId,
        to: RegionId,
    },
    CancelDrainStart {
        task_id: TaskId,
    },
    CancelDrainComplete {
        task_id: TaskId,
        checkpoints: u32,
    },

    // === Obligations ===
    ObligationReserve {
        obligation_id: ObligationId,
        kind: ObligationKind,
        holder: TaskId,
    },
    ObligationCommit {
        obligation_id: ObligationId,
    },
    ObligationAbort {
        obligation_id: ObligationId,
    },
    ObligationLeak {  // ERROR CASE
        obligation_id: ObligationId,
        holder: TaskId,
        region: RegionId,
    },

    // === Scheduler ===
    SchedulerPick {
        task_id: TaskId,
        lane: SchedulerLane,  // Cancel, Timed, Ready
