    // === Combinators ===
    RaceStart {
        participants: Vec<TaskId>,
    },
    RaceWinner {
        winner: TaskId,
        losers: Vec<TaskId>,
    },
    RaceLoserDrainStart {
        loser: TaskId,
    },
    RaceLoserDrainComplete {
        loser: TaskId,
    },

    // === User Events (for application tracing) ===
    User {
        name: String,
        data: TraceData,
    },
}

/// Serializable trace data for user events
#[derive(Clone, Debug, PartialEq, Eq)]
pub enum TraceData {
    None,
    Bool(bool),
    Int(i64),
    Uint(u64),
    String(String),
    List(Vec<TraceData>),
